def safe_div(a, b):
    try:
        return a / b
    except (ZeroDivisionError, TypeError):
        return None

print(safe_div(10, 0))
print(safe_div(10, "2"))

def load(s):
    try:
        data = int(s)
    except ValueError:
        print("bad input")
    else:
        print("parsed:", data)
    finally:
        print("done")

load("7")
load("x")

